"""
Pytest test suite for audit log access control requirements.

Requirement: A privacy-officer shall access audit logs scoped to their
organisation; cross-organisation access shall be forbidden. Negative paths
including permission denial, missing mandatory elements, and conflicting
state transitions must be tested.
"""

import uuid
from dataclasses import dataclass, field
from datetime import datetime, timedelta, timezone
from enum import Enum
from http import HTTPStatus
from typing import Any
from unittest.mock import MagicMock, patch

import pytest


# ---------------------------------------------------------------------------
# Domain models (stand-ins for the real application models)
# ---------------------------------------------------------------------------

class Role(str, Enum):
    PRIVACY_OFFICER = "privacy_officer"
    CLINICIAN = "clinician"
    ADMIN = "admin"
    AUDITOR = "auditor"  # system-level; can cross organisations
    ANONYMOUS = "anonymous"


class LogState(str, Enum):
    ACTIVE = "active"
    ARCHIVED = "archived"
    PURGED = "purged"       # terminal – no further transitions allowed
    LOCKED = "locked"       # under legal hold – cannot be archived or purged


@dataclass
class Organisation:
    id: str = field(default_factory=lambda: str(uuid.uuid4()))
    name: str = "Test Org"


@dataclass
class User:
    id: str = field(default_factory=lambda: str(uuid.uuid4()))
    role: Role = Role.PRIVACY_OFFICER
    organisation_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    is_active: bool = True


@dataclass
class AuditLogEntry:
    id: str = field(default_factory=lambda: str(uuid.uuid4()))
    organisation_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    actor_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    action: str = "record.view"
    resource_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    timestamp: datetime = field(
        default_factory=lambda: datetime.now(timezone.utc)
    )
    state: LogState = LogState.ACTIVE
    metadata: dict[str, Any] = field(default_factory=dict)


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------

class PermissionDeniedError(Exception):
    """Raised when a user lacks the required permission."""


class CrossOrganisationAccessError(PermissionDeniedError):
    """Raised when a user attempts to access another organisation's data."""


class MissingMandatoryFieldError(ValueError):
    """Raised when a required field is absent or None."""


class InvalidStateTransitionError(RuntimeError):
    """Raised when a requested state transition is illegal."""


class ResourceNotFoundError(LookupError):
    """Raised when the requested resource does not exist."""


class InactiveUserError(PermissionDeniedError):
    """Raised when a deactivated user attempts any action."""


# ---------------------------------------------------------------------------
# Service under test (minimal implementation to satisfy the interface)
# ---------------------------------------------------------------------------

class AuditLogService:
    """
    Service that enforces:
      - Role-based access (only PRIVACY_OFFICER and AUDITOR may read logs)
      - Organisation scoping (PRIVACY_OFFICER sees own org only)
      - Mandatory field validation on log creation
      - Legal state-machine rules
    """

    ALLOWED_READER_ROLES = {Role.PRIVACY_OFFICER, Role.AUDITOR}

    # Permitted state transitions: current → {allowed next states}
    VALID_TRANSITIONS: dict[LogState, set[LogState]] = {
        LogState.ACTIVE:   {LogState.ARCHIVED, LogState.LOCKED},
        LogState.ARCHIVED: {LogState.PURGED},
        LogState.LOCKED:   set(),          # no exit from LOCKED
        LogState.PURGED:   set(),          # terminal
    }

    def __init__(self, log_store: dict[str, AuditLogEntry] | None = None):
        self._store: dict[str, AuditLogEntry] = log_store or {}

    # ------------------------------------------------------------------
    # Public API
    # ------------------------------------------------------------------

    def get_log(self, *, requesting_user: User, log_id: str) -> AuditLogEntry:
        self._assert_active(requesting_user)
        self._assert_reader(requesting_user)
        entry = self._fetch(log_id)
        self._assert_org_scope(requesting_user, entry.organisation_id)
        return entry

    def list_logs(
        self,
        *,
        requesting_user: User,
        organisation_id: str,
        start: datetime | None = None,
        end: datetime | None = None,
    ) -> list[AuditLogEntry]:
        self._assert_active(requesting_user)
        self._assert_reader(requesting_user)
        self._assert_org_scope(requesting_user, organisation_id)

        results = [
            e for e in self._store.values()
            if e.organisation_id == organisation_id
        ]
        if start:
            results = [e for e in results if e.timestamp >= start]
        if end:
            results = [e for e in results if e.timestamp <= end]
        return results

    def create_log(
        self,
        *,
        requesting_user: User,
        organisation_id: str | None,
        actor_id: str | None,
        action: str | None,
        resource_id: str | None,
        metadata: dict[str, Any] | None = None,
    ) -> AuditLogEntry:
        """
        System-internal call (e.g. from an event processor).
        Still validates mandatory fields and active user.
        """
        self._assert_active(requesting_user)

        mandatory = {
            "organisation_id": organisation_id,
            "actor_id": actor_id,
            "action": action,
            "resource_id": resource_id,
        }
        missing = [k for k, v in mandatory.items() if not v]
        if missing:
            raise MissingMandatoryFieldError(
                f"Missing mandatory fields: {', '.join(missing)}"
            )

        entry = AuditLogEntry(
            organisation_id=organisation_id,
            actor_id=actor_id,
            action=action,
            resource_id=resource_id,
            metadata=metadata or {},
        )
        self._store[entry.id] = entry
        return entry

    def transition_state(
        self,
        *,
        requesting_user: User,
        log_id: str,
        new_state: LogState,
    ) -> AuditLogEntry:
        self._assert_active(requesting_user)
        entry = self._fetch(log_id)
        self._assert_org_scope(requesting_user, entry.organisation_id)

        allowed = self.VALID_TRANSITIONS.get(entry.state, set())
        if new_state not in allowed:
            raise InvalidStateTransitionError(
                f"Cannot transition {entry.state!r} → {new_state!r}. "
                f"Allowed: {allowed or 'none'}"
            )
        entry.state = new_state
        return entry

    # ------------------------------------------------------------------
    # Internal guards
    # ------------------------------------------------------------------

    def _assert_active(self, user: User) -> None:
        if not user.is_active:
            raise InactiveUserError(f"User {user.id} is deactivated.")

    def _assert_reader(self, user: User) -> None:
        if user.role not in self.ALLOWED_READER_ROLES:
            raise PermissionDeniedError(
                f"Role {user.role!r} is not permitted to read audit logs."
            )

    def _assert_org_scope(self, user: User, target_org_id: str) -> None:
        if user.role == Role.AUDITOR:
            return  # cross-org is explicitly allowed for system auditors
        if user.organisation_id != target_org_id:
            raise CrossOrganisationAccessError(
                f"User org {user.organisation_id!r} ≠ target org "
                f"{target_org_id!r}."
            )

    def _fetch(self, log_id: str) -> AuditLogEntry:
        try:
            return self._store[log_id]
        except KeyError:
            raise ResourceNotFoundError(f"Audit log {log_id!r} not found.")


