# 1. HAPPY-PATH: Privacy officer can access own organisation's logs
# ===========================================================================

class TestPrivacyOfficerHappyPath:

    def test_get_log_own_org_returns_entry(
        self,
        service: AuditLogService,
        privacy_officer_a: User,
        log_entry_org_a: AuditLogEntry,
    ) -> None:
        result = service.get_log(
            requesting_user=privacy_officer_a,
            log_id=log_entry_org_a.id,
        )
        assert result.id == log_entry_org_a.id

    def test_list_logs_own_org_returns_all_matching(
        self,
        service: AuditLogService,
        privacy_officer_a: User,
        org_a: Organisation,
        log_entry_org_a: AuditLogEntry,
    ) -> None:
        results = service.list_logs(
            requesting_user=privacy_officer_a,
            organisation_id=org_a.id,
        )
        ids = [r.id for r in results]
        assert log_entry_org_a.id in ids

    def test_list_logs_own_org_excludes_other_org_entries(
        self,
        service: AuditLogService,
        privacy_officer_a: User,
        org_a: Organisation,
        log_entry_org_b: AuditLogEntry,
    ) -> None:
        results = service.list_logs(
            requesting_user=privacy_officer_a,
            organisation_id=org_a.id,
        )
        ids = [r.id for r in results]
        assert log_entry_org_b.id not in ids

    def test_list_logs_date_range_filter_start(
        self,
        privacy_officer_a: User,
        org_a: Organisation,
    ) -> None:
        now = datetime.now(timezone.utc)
        old_entry = AuditLogEntry(
            organisation_id=org_a.id,
            actor_id="u1", action="a", resource_id="r1",
            timestamp=now - timedelta(days=30),
        )
        new_entry = AuditLogEntry(
            organisation_id=org_a.id,
            actor_id="u1", action="b", resource_id="r2",
            timestamp=now,
        )
        svc = AuditLogService(
            log_store={old_entry.id: old_entry, new_entry.id: new_entry}
        )
        results = svc.list_logs(
            requesting_user=privacy_officer_a,
            organisation_id=org_a.id,
            start=now - timedelta(days=1),
        )
        assert new_entry.id in [r.id for r in results]
        assert old_entry.id not in [r.id for r in results]

    def test_list_logs_date_range_filter_end(
        self,
        privacy_officer_a: User,
        org_a: Organisation,
    ) -> None:
        now = datetime.now(timezone.utc)
        old_entry = AuditLogEntry(
            organisation_id=org_a.id,
            actor_id="u1", action="a", resource_id="r1",
            timestamp=now - timedelta(days=30),
        )
        new_entry = AuditLogEntry(
            organisation_id=org_a.id,
            actor_id="u1", action="b", resource_id="r2",
            timestamp=now,
        )
        svc = AuditLogService(
            log_store={old_entry.id: old_entry, new_entry.id: new_entry}
        )
        results = svc.list_logs(
            requesting_user=privacy_officer_a,
            organisation_id=org_a.id,
            end=now - timedelta(days=1),
        )
        assert old_entry.id in [r.id for r in results]
        assert new_entry.id not in [r.id for r in results]

    def test_list_logs_returns_empty_list_when_no_entries(
        self,
        privacy_officer_a: User,
        org_a: Organisation,
    ) -> None:
        svc = AuditLogService(log_store={})
        results = svc.list_logs(
            requesting_user=privacy_officer_a,
            organisation_id=org_a.id,
        )
        assert results == []


