class TestCrossOrganisationAccessForbidden:

    def test_get_log_cross_org_raises(
        self,
        service: AuditLogService,
        privacy_officer_a: User,
        log_entry_org_b: AuditLogEntry,
    ) -> None:
        with pytest.raises(CrossOrganisationAccessError):
            service.get_log(
                requesting_user=privacy_officer_a,
                log_id=log_entry_org_b.id,
            )

    def test_list_logs_cross_org_raises(
        self,
        service: AuditLogService,
        privacy_officer_a: User,
        org_b: Organisation,
    ) -> None:
        with pytest.raises(CrossOrganisationAccessError):
            service.list_logs(
                requesting_user=privacy_officer_a,
                organisation_id=org_b.id,
            )

    def test_officer_b_cannot_read_officer_a_log(
        self,
        service: AuditLogService,
        privacy_officer_b: User,
        log_entry_org_a: AuditLogEntry,
    ) -> None:
        with pytest.raises(CrossOrganisationAccessError):
            service.get_log(
                requesting_user=privacy_officer_b,
                log_id=log_entry_org_a.id,
            )

    def test_cross_org_error_message_contains_org_ids(
        self,
        service: AuditLogService,
        privacy_officer_a: User,
        log_entry_org_b: AuditLogEntry,
        org_a: Organisation,
        org_b: Organisation,
    ) -> None:
        with pytest.raises(CrossOrganisationAccessError, match=org_a.id):
            service.get_log(
                requesting_user=privacy_officer_a,
                log_id=log_entry_org_b.id,
            )

    def test_cross_org_raises_subclass_of_permission_denied(
        self,
        service: AuditLogService,
        privacy_officer_a: User,
        log_entry_org_b: AuditLogEntry,
    ) -> None:
        """CrossOrganisationAccessError must be catchable as PermissionDenied."""
        with pytest.raises(PermissionDeniedError):
            service.get_log(
                requesting_user=privacy_officer_a,
                log_id=log_entry_org_b.id,
            )

    def test_system_auditor_can_read_any_org(
        self,
        service: AuditLogService,
        system_auditor: User,
        log_entry_org_b: AuditLogEntry,
    ) -> None:
        """System auditor is explicitly exempt from org scoping."""
        result = service.get_log(
            requesting_user=system_auditor,
            log_id=log_entry_org_b.id,
        )
        assert result.id == log_entry_org_b.id

    def test_system_auditor_can_list_any_org(
        self,
        service: AuditLogService,
        system_auditor: User,
        org_b: Organisation,
        log_entry_org_b: AuditLogEntry,
    ) -> None:
        results = service.list_logs(
            requesting_user=system_auditor,
            organisation_id=org_b.id,
        )
        assert log_entry_org_b.id in [r.id for r in results]


