class TestConflictingStateTransitions:

    def test_active_to_archived_is_permitted(
        self,
        privacy_officer_a: User,
        org_a: Organisation,
    ) -> None:
        entry = AuditLogEntry(organisation_id=org_a.id, action="a",
                              actor_id="u", resource_id="r")
        svc = AuditLogService(log_store={entry.id: entry})
        updated = svc.transition_state(
            requesting_user=privacy_officer_a,
            log_id=entry.id,
            new_state=LogState.ARCHIVED,
        )
        assert updated.state == LogState.ARCHIVED

    def test_active_to_locked_is_permitted(
        self,
        privacy_officer_a: User,
        org_a: Organisation,
    ) -> None:
